#include "mul.h"
#include <string.h>
#include "conj_values.h"

// twiddle factor struct
typedef struct {
    std::complex<float> *tw;
    uint16_t *br_lut;
    int len;
    int bits;
} TwiddleTable;

// twiddle factor generation
static TwiddleTable *tw_create(int len, int inverse) {
    TwiddleTable *t = new TwiddleTable;
    t->len = len;
    t->bits = (int)round(log2((float)len));

    t->br_lut = new uint16_t[len];
    for (int i = 0; i < len; i++) {
        int rev = 0;
        for (int b = 0; b < t->bits; b++)
            if (i & (1 << b))
                rev |= (1 << (t->bits - 1 - b));
        t->br_lut[i] = (uint16_t)rev;
    }

    int total = len - 1;
    t->tw = new std::complex<float>[total];

    float sign = inverse ? 1.0 : -1.0;
    int idx = 0;
    for (int s = 1; s <= t->bits; s++) {
        int m = 1 << s;
        int m2 = m >> 1;
        /* std::complex<float> w = cexp(I * sign * 2.0 * M_PI / m); */
        std::complex<float> w = std::polar(1.0f, sign * 2.0f * (float)M_PI / (float)m);
        std::complex<float> wn = 1.0;
        for (int j = 0; j < m2; j++) {
            t->tw[idx++] = wn;
            wn *= w;
        }
    }
    return t;
}

// de-alloc the twiddle factor struct attributes
static void tw_free(TwiddleTable *t) {
    delete[] t->tw;
    delete[] t->br_lut;
    delete t;
}

static void fft_fast(std::complex<float> *x, int len, TwiddleTable *t, int inverse) {

    // bit reversal
    uint16_t *brl = t->br_lut;
    for (int i = 0; i < len; i++) {
        int rev = brl[i];
        if (rev > i) {
            std::complex<float> tmp = x[i];
            x[i] = x[rev];
            x[rev] = tmp;
        }
    }

    // butterfly stages
    int ti = 0;
    for (int s = 1; s <= t->bits; s++) {
        int m = 1 << s;
        int m2 = m >> 1;
        for (int k = 0; k < len; k += m) {
            for (int j = 0; j < m2; j++) {
                std::complex<float> tw = t->tw[ti + j];
                std::complex<float> tm = tw * x[k + j + m2];
                std::complex<float> u = x[k + j];
                x[k + j] = u + tm;
                x[k + j + m2] = u - tm;
            }
        }
        ti += m2;
    }

    if (inverse) {
        float inv = 1.0 / len;
        for (int i = 0; i < len; i++)
            x[i] *= inv;
    }
}

void demo_mult(std::complex<float> zc[N], std::complex<float> out_zc[N])
{
    TwiddleTable *tw_512_fwd = tw_create(512, 0);

    std::complex<float> zc_base[512];
    std::complex<float> zc_tx[512 * 2];
    for (int i = 0; i < 512; i++) {
        zc_base[i] = std::polar(1.0f, -1.0f * (float)M_PI * (float)i * (float)i / 512.0f);
        zc_tx[i] = zc_base[i];
        zc_tx[512 + i] = zc_base[i];
    }

    int zc_length = 512 * 2;
    std::complex<float> ZC_MF_CONJ[512];
    memcpy(ZC_MF_CONJ, zc_base, 512 * sizeof(std::complex<float>));
    fft_fast(ZC_MF_CONJ, 512, tw_512_fwd, 0);
    for (int i = 0; i < 512; i++)
    {
        ZC_MF_CONJ[i] = std::conj(ZC_MF_CONJ[i]);
        printf("{%f,%f}\n", real(ZC_MF_CONJ[i]), imag(ZC_MF_CONJ[i]));
    }

    printf("\n\n");

    tw_free(tw_512_fwd);

    for(int i = 0; i < 512; i++)
    {
        /* out_zc[i] = zc[i] * ZC_MF_CONJ[i]; */
        out_zc[i] = zc[i] * zc_conj[i];
        /* out_zc[i] = zc[i] * (std::complex<float>){2, 2}; */
        /* out_zc[i] = zc[i]; */
    }
}

